#include <print>

template <typename... Args>
constexpr auto second(Args... args) {
    return args...[1];          // 0-based: элемент #1
}

int main() {
    std::print("{}\n", second(10, 20, 30));
}

#include <print>
#include <type_traits>

template <typename... Ts>
constexpr auto last(Ts... xs) {
    return xs...[sizeof...(Ts) - 1];        // value-форма
}

template <typename... Ts>
using last_t = Ts...[sizeof...(Ts) - 1];    // type-форма

int main() {
    static_assert(std::is_same_v<last_t<int, double, char>, char>);
    std::print("{}\n", last(1, 2, 3));
}

#include <print>

template <typename... Ts>
Ts...[0] first_of(Ts... xs) {       // тип возврата — первый тип пака
    return xs...[0];
}

int main() {
    std::print("{}\n", first_of(3.14, 1, 'x'));
}

#include <print>

template <typename... Ts>
constexpr int tweak(Ts... xs) {
    auto& r = xs...[0];      // xs...[0] именует первый параметр -> lvalue
    r += 5;                  // меняем через ссылку
    return xs...[0];
}

int main() {
    std::print("{}\n", tweak(10, 20, 30));
}

#include <print>

// Доступна только если в паке есть индекс 2 (минимум 3 элемента)
template <typename... Ts>
auto third(Ts... xs) -> decltype(xs...[2]) {
    return xs...[2];
}

// Запасной вариант для более коротких паков
template <typename... Ts>
int third(Ts...) {
    return -1;
}

int main() {
    std::print("{}\n", third(10, 20));
}

