std::mutex mtx;

std::tuple<int, int, int> stats() { return {1, 2, 3}; }

int main() {
    auto [total, _, count] = stats(); // средний элемент не нужен

    {
        std::lock_guard<std::mutex> _{mtx}; // держим лок до конца блока
        std::print("{} / {}\n", total, count);
    }
}

