#include <print>
#include <tuple>

std::tuple<int, int, int> minmax_sum(int a, int b, int c) {
    int mn = a < b ? (a < c ? a : c) : (b < c ? b : c);
    int mx = a > b ? (a > c ? a : c) : (b > c ? b : c);
    return {mn, a + b + c, mx};
}

int main() {
    auto [lo, _, hi] = minmax_sum(5, 2, 9);
    std::print("{} {}\n", lo, hi);
}
